class Solution(object):
    def shortestToChar(self, s, c):
        n = len(s)
        result = [n] * n
        last_pos = -n
        for i in range(n):
            if s[i] == c:
                last_pos = i
            result[i] = min(result[i], i - last_pos)
        last_pos = 2 * n
        for i in range(n-1, -1, -1):
            if s[i] == c:
                last_pos = i
            result[i] = min(result[i], last_pos - i)
        return result
